defmodule CaravelaDemoWeb.Schema.LibraryQueries do
  @moduledoc """
  Generated by Caravela from CaravelaDemo.Domains.Library.

  Absinthe query object. Each entity exposes:

    * `<entity>` — fetch a single record by id
    * `<entities>` — list all records visible to the caller

  Context (authorization, tenant) is extracted from the Absinthe
  resolution via `extract_context/1`.

  Regenerate with `mix caravela.gen.graphql CaravelaDemo.Domains.Library`.
  Custom code placed below the `# --- CUSTOM ---` marker is preserved.
  """

  use Absinthe.Schema.Notation

  alias CaravelaDemo.Library

  object :library_queries do
    @desc "List authors"
    field :authors, list_of(:author) do
      resolve(fn _parent, _args, resolution ->
        {:ok, Library.list_authors(extract_context(resolution))}
      end)
    end

    @desc "Fetch a single author by id"
    field :author, :author do
      arg(:id, non_null(:id))

      resolve(fn _parent, %{id: id}, resolution ->
        {:ok, Library.get_author(id, extract_context(resolution))}
      end)
    end

    @desc "List books"
    field :books, list_of(:book) do
      resolve(fn _parent, _args, resolution ->
        {:ok, Library.list_books(extract_context(resolution))}
      end)
    end

    @desc "Fetch a single book by id"
    field :book, :book do
      arg(:id, non_null(:id))

      resolve(fn _parent, %{id: id}, resolution ->
        {:ok, Library.get_book(id, extract_context(resolution))}
      end)
    end

    @desc "List publishers"
    field :publishers, list_of(:publisher) do
      resolve(fn _parent, _args, resolution ->
        {:ok, Library.list_publishers(extract_context(resolution))}
      end)
    end

    @desc "Fetch a single publisher by id"
    field :publisher, :publisher do
      arg(:id, non_null(:id))

      resolve(fn _parent, %{id: id}, resolution ->
        {:ok, Library.get_publisher(id, extract_context(resolution))}
      end)
    end
  end

  # --- Internal --------------------------------------------------------

  defp extract_context(%{context: context}) when is_map(context), do: context
  defp extract_context(_), do: %{}

  # --- CUSTOM ---
  # Custom code below this line is preserved on regeneration.
end
